// Dashboard 7 — TSQMI com Pulso ECG
// Implementação limpa e funcional

const REPO_META = {
  cli:     { label: 'CLI',     color: '#1D9E75' },
  core:    { label: 'Core',    color: '#378ADD' },
  service: { label: 'Service', color: '#D85A30' },
  front:   { label: 'Front',   color: '#D4537E' }
};

// Função msgPulse - Gera pulso ECG para uma transição
function msgPulse(valueA, valueB, timeA, timeB) {
  const SPS = 12; // 12 pontos por transição
  const points = [];
  const delta = valueB - valueA;
  const peakAmplitude = delta * 2.2; // Amplitude do pico 2.2x maior que delta

  // Usar intervalo de tempo fixo de 2 horas entre pontos para garantir visibilidade
  const TWO_HOURS = 2 * 60 * 60 * 1000;
  const timeStep = TWO_HOURS;

  for (let i = 0; i < SPS; i++) {
    const t = i / SPS;
    let v;

    if (t < 0.30) {
      // Base inicial - 30% do tempo no valor inicial
      v = valueA;
    } else if (t < 0.42) {
      // Subida - 12% do tempo subindo ao pico
      const p = (t - 0.30) / 0.12;
      v = valueA + peakAmplitude * Math.sin(p * Math.PI * 0.5);
    } else if (t < 0.56) {
      // Descida - 14% do tempo descendo do pico
      const p = (t - 0.42) / 0.14;
      v = valueA + peakAmplitude * (1 - p);
    } else if (t < 0.68) {
      // Onda de retorno - 12% do tempo com pequena oscilação abaixo do novo valor
      const p = (t - 0.56) / 0.12;
      v = valueB - (delta * 0.15) * Math.sin(p * Math.PI);
    } else {
      // Nova base - 32% do tempo no novo valor
      v = valueB;
    }

    const interpTime = timeA + (timeStep * i);
    points.push([interpTime, v]);
  }

  return points;
}

// Processar dados do PostgreSQL
const repoData = {};
data.series.forEach(series => {
  const refId = series.refId.toLowerCase();
  if (REPO_META[refId]) {
    const timeField = series.fields.find(f => f.name === 'time');
    const valueField = series.fields.find(f => f.name === series.refId);

    if (timeField && valueField && valueField.values.length > 0) {
      repoData[refId] = {
        label: REPO_META[refId].label,
        color: REPO_META[refId].color,
        times: timeField.values,
        values: valueField.values
      };
    }
  }
});

const repos = Object.keys(repoData);
if (repos.length === 0) {
  return {
    title: {
      text: 'Aguardando dados...',
      left: 'center',
      top: 'center',
      textStyle: { fontSize: 14, color: '#888' }
    }
  };
}

const firstRepo = repos[0];
const N = repoData[firstRepo].values.length;

// Releases
const releases = [
  { label: 'R1', dateIndex: 0 },
  { label: 'R2', dateIndex: Math.floor(N / 2) },
  { label: 'RN', dateIndex: N - 1 }
];

// Criar séries com pulso ECG
const series = repos.map(repoKey => {
  const repo = repoData[repoKey];
  const values = repo.values;
  const times = repo.times;

  // Detectar transições
  const transitions = [];
  for (let i = 0; i < values.length - 1; i++) {
    if (values[i] !== values[i + 1]) {
      transitions.push({
        startIdx: i,
        endIdx: i + 1,
        valueA: values[i],
        valueB: values[i + 1],
        timeA: times[i],
        timeB: times[i + 1]
      });
    }
  }

  // Criar índices de transição para pular na linha plana
  const transitionSet = new Set();
  transitions.forEach(t => {
    transitionSet.add(t.startIdx);
    transitionSet.add(t.endIdx);
  });

  // Construir dados finais
  const dataPoints = [];

  // Adicionar pontos da linha plana (exceto transições)
  for (let i = 0; i < values.length; i++) {
    if (!transitionSet.has(i)) {
      dataPoints.push([times[i], values[i]]);
    }
  }

  // Adicionar pulsos ECG
  transitions.forEach(trans => {
    const pulsePoints = msgPulse(trans.valueA, trans.valueB, trans.timeA, trans.timeB);
    dataPoints.push(...pulsePoints);

    // DEBUG: Log da primeira transição do Core
    if (repo.label === 'Core' && transitions.indexOf(trans) === 0) {
      console.log('DEBUG Core - Primeira transição:');
      console.log('  valueA:', trans.valueA, 'valueB:', trans.valueB);
      console.log('  timeA:', new Date(trans.timeA));
      console.log('  timeB:', new Date(trans.timeB));
      console.log('  Pontos gerados:', pulsePoints.length);
      pulsePoints.forEach((pt, idx) => {
        console.log('    [' + idx + ']', new Date(pt[0]).toISOString(), 'valor:', pt[1].toFixed(4));
      });
    }
  });

  // Ordenar por timestamp
  dataPoints.sort((a, b) => a[0] - b[0]);

  return {
    name: repo.label,
    type: 'line',
    smooth: false,
    symbol: 'circle',
    symbolSize: 4,
    showSymbol: true,
    sampling: 'none',
    connectNulls: false,
    lineStyle: {
      color: repo.color,
      width: 2,
      type: 'solid'
    },
    itemStyle: {
      color: repo.color
    },
    data: dataPoints,
    markLine: {
      silent: true,
      symbol: 'none',
      data: releases.map(rel => ({
        xAxis: times[rel.dateIndex],
        label: {
          formatter: rel.label,
          position: 'insideStartTop',
          fontSize: 9,
          fontWeight: 'bold',
          color: '#BA7517'
        },
        lineStyle: {
          color: '#BA7517',
          type: 'dashed',
          width: 1
        }
      }))
    },
    markPoint: {
      symbol: 'circle',
      symbolSize: 6,
      data: releases.map(rel => ({
        coord: [times[rel.dateIndex], values[rel.dateIndex]],
        itemStyle: { color: repo.color }
      }))
    }
  };
});

const isDark = theme.isDark;
const textColor = isDark ? 'rgba(255,255,255,0.7)' : 'rgba(0,0,0,0.6)';
const gridColor = isDark ? 'rgba(255,255,255,0.07)' : 'rgba(0,0,0,0.07)';

return {
  backgroundColor: 'transparent',
  legend: {
    data: repos.map(k => repoData[k].label),
    textStyle: { color: textColor, fontSize: 11 },
    bottom: 0
  },
  tooltip: {
    trigger: 'axis',
    formatter: params => {
      if (!params || params.length === 0) return '';

      const time = params[0].data[0];
      const dt = new Date(time).toLocaleString('pt-BR');

      let html = '<b>' + dt + '</b>';

      params.forEach(p => {
        const val = p.data[1];
        html += '<br/><span style="color:' + p.color + '">■</span> ' + p.seriesName + ': <b>' + val.toFixed(4) + '</b>';
      });

      return html;
    }
  },
  grid: { top: 20, bottom: 50, left: 50, right: 20 },
  xAxis: {
    type: 'time',
    axisLabel: {
      color: textColor,
      fontSize: 10,
      formatter: function(value) {
        const d = new Date(value);
        return String(d.getDate()).padStart(2, '0') + '/' + String(d.getMonth() + 1).padStart(2, '0');
      }
    },
    splitLine: { show: false },
    axisLine: { lineStyle: { color: gridColor } }
  },
  yAxis: {
    type: 'value',
    scale: true,
    axisLabel: {
      color: textColor,
      fontSize: 9,
      formatter: v => v.toFixed(3)
    },
    splitLine: { lineStyle: { color: gridColor } }
  },
  series
};

options.getOption:
// ═══════════════════════════════════════════════════════════════════════════
// Dashboard de Pulso — TSQMI por Repositório com Releases
// Um gráfico ECG para cada repositório • Layout vertical empilhado
// ═══════════════════════════════════════════════════════════════════════════

try {
  const panelData = context.panel.data;
  if (!panelData || !panelData.series || panelData.series.length === 0) {
    return { title: { text: 'Sem dados disponíveis', left: 'center', top: 'center' } };
  }

  function toArr(field) {
    if (!field) return [];
    const v = field.values;
    if (!v) return [];
    if (v.buffer) return Array.from(new Float64Array(v.buffer));
    if (Array.isArray(v)) return v;
    if (typeof v.toArray === 'function') return v.toArray();
    return Array.from(v);
  }

  const frame = panelData.series[0];
  if (!frame || frame.fields.length === 0) {
    return { title: { text: 'Query A sem retorno', left: 'center', top: 'center' } };
  }

  // ── 1. Extração de Dados Principais (Query A) ──────────────────────────────
  const names = toArr(frame.fields.find(f => f.name === 'name'));
  const rawDatetimes = toArr(frame.fields.find(f => f.name === 'datetime'));
  const tsqmis = toArr(frame.fields.find(f => f.name === 'tsqmi'));

  const datetimes = rawDatetimes.map(ts => {
    const d = new Date(Number(ts));
    if (isNaN(d.getTime())) return String(ts);
    const yyyy = d.getFullYear();
    const mm = String(d.getMonth() + 1).padStart(2, '0');
    const dd = String(d.getDate()).padStart(2, '0');
    return `${yyyy}-${mm}-${dd}`;
  });

  // ── 2. Extração de Releases (Query B) ──────────────────────────────────────
  let releaseNames = [], releaseDates = [], releaseRepos = [];
  if (panelData.series.length > 1) {
    const relFrame = panelData.series[1];
    releaseNames = toArr(relFrame.fields.find(f => f.name === 'release_name'));
    releaseDates = toArr(relFrame.fields.find(f => f.name === 'release_date'));
    releaseRepos = toArr(relFrame.fields.find(f => f.name === 'repository_name'));
  }

  // ── 3. Agrupamento por Repositório ─────────────────────────────────────────
  const groupedData = {};
  for (let i = 0; i < names.length; i++) {
    const repoName = names[i];
    if (!groupedData[repoName]) {
      groupedData[repoName] = { datetimes: [], tsqmi: [] };
    }
    groupedData[repoName].datetimes.push(datetimes[i]);
    groupedData[repoName].tsqmi.push(tsqmis[i]);
  }

  const REPO_COLORS = ['#00D9C9', '#0080FF', '#FF6B35', '#BA7517', '#1D9E75', '#378ADD', '#D85A30', '#D4537E', '#7F77DD'];

  const repositories = Object.keys(groupedData).sort().map((name, idx) => ({
    name,
    label: name.length > 30 ? name.substring(0, 27) + '...' : name,
    color: REPO_COLORS[idx % REPO_COLORS.length],
    datetimes: groupedData[name].datetimes,
    tsqmi: groupedData[name].tsqmi,
  }));

  // ── Função de pulso MSG ────────────────────────────────────────────────────
  function msgPulse(scores, idxList) {
    const SPS = 60;
    const pts = [];
    for (let ii = 0; ii < idxList.length - 1; ii++) {
      const a = scores[idxList[ii]] ?? 0, b = scores[idxList[ii + 1]] ?? 0;
      const delta = b - a, pk = delta * 2.2;
      for (let s = 0; s < SPS; s++) {
        const t = s / SPS;
        let v;
        if (t < 0.30) { v = a; }
        else if (t < 0.42) { const p = (t - 0.30) / 0.12; v = a + pk * Math.sin(p * Math.PI * 0.5); }
        else if (t < 0.56) { const p = (t - 0.42) / 0.14; v = a + pk * (1 - p); }
        else if (t < 0.68) { const p = (t - 0.56) / 0.12; v = b - delta * 0.15 * Math.sin(p * Math.PI); }
        else { v = b; }
        pts.push(Math.max(0.01, Math.min(0.99, v)));
      }
    }
    pts.push(Math.max(0.01, Math.min(0.99, scores[idxList[idxList.length - 1]] ?? 0)));
    return pts;
  }

  const SPS = 60;
  const nRepos = repositories.length;
  const isDark = context.grafana.theme.isDark;
  const textColor = isDark ? 'rgba(255,255,255,0.7)' : 'rgba(0,0,0,0.6)';
  const gridColor = isDark ? 'rgba(255,255,255,0.07)' : 'rgba(0,0,0,0.07)';
  const mainTextColor = isDark ? '#ffffff' : '#333333';

  // Layout param
  const topPad = 8, bottomPad = 10, gap = 4;
  const totalH = 100 - topPad - bottomPad;
  const rowH = (totalH - gap * (nRepos - 1)) / nRepos;

  const grids = repositories.map((_, i) => ({
    show: true,
    borderWidth: 1,
    borderColor: gridColor,
    backgroundColor: isDark ? 'rgba(255, 255, 255, 0.02)' : 'rgba(0, 0, 0, 0.02)',
    top: `${topPad + i * (rowH + gap)}%`,
    height: `${rowH}%`,
    left: '200px',
    right: '20px',
  }));

  const xAxes = [];
  const yAxes = [];
  const series = [];

  // ── 4. Construção Dinâmica por Repositório ─────────────────────────────────
  repositories.forEach((repo, repoIdx) => {
    const N = repo.datetimes.length;
    const idxList = Array.from({ length: N }, (_, i) => i);

    const xAxisData = [];
    if (N > 0) {
      for (let i = 0; i < N - 1; i++) {
        xAxisData.push(repo.datetimes[i]);
        for (let s = 1; s < SPS; s++) xAxisData.push('');
      }
      xAxisData.push(repo.datetimes[N - 1]);
    }

    xAxes.push({
      type: 'category',
      gridIndex: repoIdx,
      data: xAxisData,
      axisLabel: {
        show: repoIdx === nRepos - 1,
        color: textColor,
        fontSize: 10,
        interval: (index, value) => value !== '',
        formatter: (value) => value ? String(value).slice(5, 10).replace('-', '/') : ''
      },
      axisTick: {
        show: true,
        interval: (index, value) => value !== '',
        length: 5
      },
      axisLine: { lineStyle: { color: gridColor } },
      splitLine: { show: false },
    });

    yAxes.push({
      type: 'value',
      gridIndex: repoIdx,
      min: 0, max: 1,
      interval: 0.5,
      axisLabel: {
        color: textColor, fontSize: 8,
        formatter: v => v === 0 ? '0' : v === 0.5 ? '' : '1',
      },
      splitLine: { lineStyle: { color: gridColor } },
    });

    // Processamento de Releases
    const datetimesMs = repo.datetimes.map(d => new Date(d).getTime());
    const timeStart = datetimesMs[0];
    const timeEnd = datetimesMs[datetimesMs.length - 1];
    const repoReleases = [];

    for (let i = 0; i < releaseNames.length; i++) {
      if (releaseRepos[i] === repo.name && releaseNames[i]) {
        const rawDate = releaseDates[i];
        let rDate = new Date(rawDate);
        if (isNaN(rDate.getTime()) && !isNaN(Number(rawDate))) {
          rDate = new Date(Number(rawDate));
        }
        const rTime = rDate.getTime();

        if (!isNaN(rTime) && rTime >= timeStart && rTime <= timeEnd) {
          let closestIdx = 0;
          let minDiff = Infinity;
          for (let j = 0; j < datetimesMs.length; j++) {
            const diff = Math.abs(datetimesMs[j] - rTime);
            if (diff < minDiff) {
              minDiff = diff;
              closestIdx = j;
            }
          }
          repoReleases.push({ label: releaseNames[i], dateIndex: closestIdx });
        }
      }
    }

    const cardColor = '#FAD02C';

    const markLineData = repoReleases.map(r => ({
      xAxis: r.dateIndex * SPS,
      label: {
        show: true,
        formatter: r.label,
        position: 'end',
        color: '#000000',
        backgroundColor: cardColor,
        padding: [4, 8, 4, 8],
        borderRadius: 4,
        fontSize: 10,
        fontWeight: 'bold',
        distance: 5
      },
      lineStyle: { color: cardColor, type: 'dashed', width: 1.5 },
    }));

    series.push({
      name: repo.label,
      type: 'line',
      xAxisIndex: repoIdx,
      yAxisIndex: repoIdx,
      smooth: false,
      symbol: 'none',
      lineStyle: { color: repo.color, width: 2 },
      data: msgPulse(repo.tsqmi, idxList),
      markLine: markLineData.length > 0 ? {
        silent: true,
        symbol: ['none', 'none'],
        data: markLineData,
      } : undefined,
      markPoint: repoReleases.length > 0 ? {
        symbol: 'circle', symbolSize: 6,
        data: repoReleases.map(r => ({
          coord: [r.dateIndex * SPS, repo.tsqmi[r.dateIndex] ?? 0],
          itemStyle: { color: cardColor, borderColor: isDark ? '#181b1f' : '#fff', borderWidth: 1 },
        })),
      } : undefined
    });
  });

  // ── Stat boxes (Alinhados à esquerda e centralizados no eixo Y) ────────────
  // ── Stat boxes (Alinhados à esquerda e centralizados no eixo Y) ────────────
  // ── Stat boxes (Alinhados à esquerda e centralizados no eixo Y) ────────────
  // ── Stat boxes (Alinhados à esquerda e centralizados no eixo Y) ────────────
  const statGraphics = repositories.map((repo, i) => {
    const nVals = repo.tsqmi.length;
    const lastValue = nVals > 0 ? repo.tsqmi[nVals - 1] ?? 0 : 0;
    const prevValue = nVals > 1 ? repo.tsqmi[nVals - 2] ?? null : null;

    let varText = '0.00%';
    let varColor = textColor;
    let arrow = '';

    // Cálculo da variação percentual (se houver histórico)
    if (prevValue !== null) {
      const delta = lastValue - prevValue;
      if (prevValue !== 0) {
        const pct = (delta / prevValue) * 100;
        arrow = pct > 0 ? '▲ ' : (pct < 0 ? '▼ ' : '');
        varText = `${arrow}${Math.abs(pct).toFixed(2)}%`;
        varColor = pct > 0 ? '#1D9E75' : (pct < 0 ? '#E24B4A' : textColor);
      } else if (lastValue > 0) {
        varText = '▲ 100.00%';
        varColor = '#1D9E75';
      }
    }

    // Calcula exatamente a porcentagem de eixo central da caixa do gráfico
    const yCenterPct = topPad-3 + i * (rowH + gap) + (rowH / 2);

    // Fator de compensação em pixels para centralizar verticalmente o bloco
    const elevation = -10;

    return {
      type: 'group',
      left: 10,
      top: `${yCenterPct}%`, // Fixa a âncora no centro matemático do gráfico
      children: [
        // Nome do repositório (Trazido mais para perto do número grande: -14)
        {
          type: 'text',
          left: 0,
          top: -14 + elevation,
          style: {
            text: repo.label,
            fontSize: 11,
            fontWeight: 'normal',
            fill: mainTextColor,
            textBaseline: 'bottom' // Alinha pela base da letra, ajudando a colar no número
          }
        },
        // Valor numérico TSQMI (No eixo 0)
        {
          type: 'text',
          left: 0,
          top: 0 + elevation,
          style: {
            text: lastValue.toFixed(3),
            fontSize: 32,
            fontWeight: 'bold',
            fill: repo.color,
            textBaseline: 'middle' // Alinha pelo meio
          }
        },
        // Variação percentual (Afastada para baixo para evitar sobreposição: +30)
        {
          type: 'text',
          left: 0,
          top: 30 + elevation,
          style: {
            text: varText,
            fontSize: 11,
            fontWeight: 'bold',
            fill: varColor,
            textBaseline: 'top' // Alinha pelo topo da letra para respeitar o vão de 30px
          }
        },
      ],
    };
  });
  // ── Título, subtítulo e Rodapé ─────────────────────────────────────────────
  const titleGraphic = {
    type: 'group',
    left: 200,
    top: 0,
    children: [
      { type: 'text', left: 0, top: 0, style: { text: 'Dashboard de Pulso — TSQMI por Repositório', fontSize: 16, fontWeight: 'bold', fill: mainTextColor } },
      { type: 'text', left: 0, top: 20, style: { text: 'Gráfico MSG de qualidade • pico = variação entre medições', fontSize: 11, fill: textColor } },
    ],
  };

  const totalMeasurements = repositories.reduce((sum, r) => sum + r.tsqmi.length, 0);

  // Extração global da última data aferida (considerando que todos os arrays compartilham o limite de tempo)
  const globalLastDate = datetimes[datetimes.length - 1] || 'N/A';

  const footerGraphic = {
    type: 'text', left: 'center', bottom: 0,
    style: { text: `${repositories.length} repositórios • ${totalMeasurements} medições totais · Última medição: ${globalLastDate} · ● = release`, fontSize: 10, fill: textColor },
  };

  // ── 5. Toolbox e Botão Clicável ────────────────────────────────────────────

  // Função centralizada para não repetir código
  function exportCSV() {
    let csv = 'Repositório,Data,TSQMI\n';
    repositories.forEach(repo => {
      repo.tsqmi.forEach((val, idx) => {
        if (val !== null && val !== undefined) {
          const date = repo.datetimes[idx];
          csv += `${repo.name},${date},${val.toFixed(4)}\n`;
        }
      });
    });
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', `tsqmi_export_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.display = 'none';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  }

  const toolbox = {
    show: true,
    feature: {
      myExportCsv: {
        show: true,
        title: 'Exportar CSV',
        icon: 'path://M14 2H6C4.89 2 4 2.9 4 4V20C4 21.11 4.89 22 6 22H18C19.11 22 20 21.11 20 20V8L14 2M18 20H6V4H13V9H18V20M12 19L8 15H10.5V12H13.5V15H16L12 19Z',
        onclick: exportCSV
      }
    },
    right: 40,
    top: 0
  };

  const exportGroupGraphic = {
    type: 'group',
    right: 40,
    top: 0,
    children: [
      {
        type: 'text',
        left: -85,
        top: 7,
        style: {
          text: 'exportar .csv',
          fontSize: 12,
          fontWeight: 'bold',
          fill: textColor
        }
      },
      {
        type: 'rect',
        left: -90,
        top: 0,
        shape: {
          width: 120,
          height: 30
        },
        style: {
          fill: 'transparent'
        },
        cursor: 'pointer',
        onclick: exportCSV,
        z: 100
      }
    ]
  };

  return {
    backgroundColor: 'transparent',
    graphic: [titleGraphic, ...statGraphics, footerGraphic, exportGroupGraphic],
    toolbox: toolbox,
    tooltip: {
      trigger: 'axis',
      axisPointer: { type: 'line' },
      formatter: params => {
        const p = params[0];
        const repoIdx = p.seriesIndex;
        const repo = repositories[repoIdx];
        const N = repo.tsqmi.length;
        const measureIdx = Math.min(Math.floor(p.dataIndex / SPS), N - 1);
        const v = repo.tsqmi[measureIdx] ?? 0;
        const prev = measureIdx > 0 ? (repo.tsqmi[measureIdx - 1] ?? null) : null;
        const delta = prev !== null ? v - prev : null;
        const dt = repo.datetimes[measureIdx];

        let html = `<b>${dt}</b>`;
        html += `<br/><span style="color:${repo.color}">■</span> ${repo.label}: <b>${v.toFixed(4)}</b>`;
        if (delta !== null) {
          const col = delta >= 0 ? '#1D9E75' : '#E24B4A';
          html += ` <span style="color:${col}">${delta >= 0 ? '+' : ''}${delta.toFixed(4)}</span>`;
        }
        return html;
      },
    },
    grid: grids,
    xAxis: xAxes,
    yAxis: yAxes,
    series,
  };
} catch (e) {
  return { title: { text: 'Erro: ' + e.message, left: 'center', top: 'center' } };
}

